using UnityEngine; public class GameplayManager : MonoBehaviour { public static GameplayManager Instance { get; private set; } [SerializeField] private ZombieSpawner spawner; public int activeZombieCount = 0; private void Awake() { if (Instance == null) { Instance = this; } else { Destroy(gameObject); } } public void RegisterZombie() { activeZombieCount++; } public void UnregisterZombie() { activeZombieCount = Mathf.Max(0, activeZombieCount - 1); } }